import unittest
from unittest.mock import Mock

class StoragePool:
    def __init__(self):
        self.volumes = {}
        self.hosts = {}

    def add_volume(self, volume_name):
        self.volumes[volume_name] = None

    def remove_volume(self, volume_name):
        if volume_name in self.volumes:
            del self.volumes[volume_name]

    def get_volume_list(self):
        return list(self.volumes.keys())

    def associate_volume_with_host(self, volume_name, host_name):
        if volume_name in self.volumes:
            self.volumes[volume_name] = host_name
            self.hosts[host_name] = volume_name

    def get_orphaned_volumes(self):
        return [volume for volume, host in self.volumes.items() if host is None]

class TestStoragePool(unittest.TestCase):
    def setUp(self):
        self.storage_pool = StoragePool()

    def test_add_volume(self):
        self.storage_pool.add_volume('volume1')
        self.assertIn('volume1', self.storage_pool.get_volume_list())

    def test_remove_volume(self):
        self.storage_pool.add_volume('volume2')
        self.storage_pool.remove_volume('volume2')
        self.assertNotIn('volume2', self.storage_pool.get_volume_list())

    def test_get_orphaned_volumes(self):
        self.storage_pool.add_volume('volume3')
        self.storage_pool.add_volume('volume4')
        self.storage_pool.associate_volume_with_host('volume3', 'host1')
        orphaned_volumes = self.storage_pool.get_orphaned_volumes()
        self.assertIn('volume4', orphaned_volumes)
        self.assertNotIn('volume3', orphaned_volumes)

if __name__ == '__main__':
    unittest.main()
```

